import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getAllDoctors, bookAppointment } from '../services/api';
import Navbar from '../components/Navbar';

const SLOTS = ['09:00 AM','10:00 AM','11:00 AM','12:00 PM','02:00 PM','03:00 PM','04:00 PM','05:00 PM'];

const BookAppointment = () => {
  const navigate = useNavigate();
  const [doctors,  setDoctors]  = useState([]);
  const [selDoc,   setSelDoc]   = useState('');
  const [date,     setDate]     = useState('');
  const [selSlot,  setSelSlot]  = useState('');
  const [symptoms, setSymptoms] = useState('');
  const [loading,  setLoading]  = useState(false);
  const [msg,      setMsg]      = useState({ type: '', text: '' });

  useEffect(() => {
    getAllDoctors().then(r => setDoctors(r.data)).catch(console.log);

    const pre = sessionStorage.getItem('preDoc');
    if (pre) {
      setSelDoc(pre);
      sessionStorage.removeItem('preDoc');
    }

    const today = new Date().toISOString().split('T')[0];
    setDate(today);
  }, []);

  const selDoctorObj = doctors.find(d => d._id === selDoc);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!selDoc) return setMsg({ type: 'er', text: 'Please select a doctor.' });
    if (!date) return setMsg({ type: 'er', text: 'Please select a date.' });
    if (!selSlot) return setMsg({ type: 'er', text: 'Please select a time slot.' });
    if (!symptoms.trim()) return setMsg({ type: 'er', text: 'Please describe your symptoms.' });

    setLoading(true);
    setMsg({ type: '', text: '' });

    try {
      await bookAppointment({
        doctorId: selDoc,
        appointmentDate: date,
        timeSlot: selSlot,
        symptoms
      });

      setMsg({ type: 'ok', text: '✅ Appointment booked successfully! Redirecting...' });
      setTimeout(() => navigate('/appointments'), 1500);
    } catch (err) {
      setMsg({ type: 'er', text: err.response?.data?.message || 'Booking failed. Please try again.' });
    } finally {
      setLoading(false);
    }
  };

  const today = new Date().toISOString().split('T')[0];

  return (
    <div style={S.page}>
      <Navbar />

      {/* 🌄 Background Overlay */}
      <div style={S.overlay}></div>

      <div style={S.wrap}>
        {/* Header */}
        <div style={S.header}>
          <button style={S.backBtn} onClick={() => navigate('/dashboard')}>← Back</button>
          <div>
            <h1 style={S.title}>Book an Appointment</h1>
            <p style={S.subtitle}>Schedule your visit easily</p>
          </div>
        </div>

        <div style={S.layout}>
          {/* LEFT FORM */}
          <div style={S.formCard}>

            {msg.text && (
              <div style={msg.type === 'ok' ? S.msgOk : S.msgEr}>
                {msg.text}
              </div>
            )}

            {/* Doctor Selection */}
            <div style={S.section}>
              <h3 style={S.sectionTitle}>Select Doctor</h3>

              {doctors.map(d => (
                <div key={d._id}
                  style={{
                    ...S.docOption,
                    ...(selDoc === d._id ? S.docSelected : {})
                  }}
                  onClick={() => setSelDoc(d._id)}
                >
                  <div style={S.docIcon}>
                    {d.userId?.name?.[0] || '👨‍⚕️'}
                  </div>

                  <div>
                    <div style={S.docName}>{d.userId?.name}</div>
                    <div style={S.docSpec}>
                      {d.specialization} · ₹{d.consultationFee}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Date */}
            <div style={S.section}>
              <h3 style={S.sectionTitle}>Select Date</h3>
              <input
                style={S.input}
                type="date"
                value={date}
                min={today}
                onChange={e => setDate(e.target.value)}
              />
            </div>

            {/* Slots */}
            <div style={S.section}>
              <h3 style={S.sectionTitle}>Select Time Slot</h3>
              <div style={S.slotsGrid}>
                {SLOTS.map(slot => (
                  <div key={slot}
                    style={{
                      ...S.slot,
                      ...(selSlot === slot ? S.slotActive : {})
                    }}
                    onClick={() => setSelSlot(slot)}
                  >
                    {slot}
                  </div>
                ))}
              </div>
            </div>

            {/* Symptoms */}
            <div style={S.section}>
              <h3 style={S.sectionTitle}>Symptoms</h3>
              <textarea
                style={{ ...S.input, height: 90 }}
                value={symptoms}
                onChange={e => setSymptoms(e.target.value)}
                placeholder="Describe your symptoms..."
              />
            </div>

            <button
              style={{ ...S.submitBtn, opacity: loading ? 0.7 : 1 }}
              onClick={handleSubmit}
              disabled={loading}
            >
              {loading ? 'Booking...' : 'Confirm Appointment'}
            </button>
          </div>

          {/* RIGHT SUMMARY */}
          <div style={S.summaryCard}>
            <h3>Summary</h3>

            {selDoctorObj ? (
              <>
                <p><strong>Doctor:</strong> {selDoctorObj.userId?.name}</p>
                <p><strong>Specialization:</strong> {selDoctorObj.specialization}</p>
                <p><strong>Date:</strong> {date || '-'}</p>
                <p><strong>Time:</strong> {selSlot || '-'}</p>
                <p><strong>Fee:</strong> ₹{selDoctorObj.consultationFee}</p>
              </>
            ) : (
              <p>Select doctor to see summary</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const S = {
  page: {
    minHeight: '100vh',
    backgroundImage: 'url("images/hospital.png")',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    position: 'relative'
  },

  overlay: {
    position: 'absolute',
    inset: 0,
    background: 'rgba(0,0,0,0.5)',
    backdropFilter: 'blur(3px)'
  },

  wrap: {
    position: 'relative',
    zIndex: 2,
    maxWidth: 1100,
    margin: '0 auto',
    padding: 30
  },

  header: {
    display: 'flex',
    gap: 15,
    marginBottom: 20,
    color: '#fff'
  },

  backBtn: {
    padding: '8px 12px',
    borderRadius: 8,
    border: 'none',
    cursor: 'pointer'
  },

  title: {
    fontSize: 26,
    fontWeight: 700
  },

  subtitle: {
    fontSize: 14,
    opacity: 0.9
  },

  layout: {
    display: 'grid',
    gridTemplateColumns: '1fr 300px',
    gap: 20
  },

  formCard: {
    background: 'rgba(255,255,255,0.95)',
    padding: 20,
    borderRadius: 12
  },

  summaryCard: {
    background: 'rgba(255,255,255,0.95)',
    padding: 20,
    borderRadius: 12
  },

  section: {
    marginBottom: 20
  },

  sectionTitle: {
    fontWeight: 600,
    marginBottom: 10
  },

  docOption: {
    padding: 10,
    border: '1px solid #ddd',
    borderRadius: 8,
    marginBottom: 8,
    cursor: 'pointer',
    display: 'flex',
    gap: 10,
    alignItems: 'center'
  },

  docSelected: {
    border: '2px solid #6366f1',
